public int maximum69Number (int num) {
    String numStr = Integer.toString(num);
    char[] numArr = numStr.toCharArray();
    for (int i = 0; i < numArr.length; i++) {
        if (numArr[i] == '6') {
            numArr[i] = '9';
            break;
        }
    }
    return Integer.parseInt(new String(numArr));
}
